create table dirkspzm32.lvs_lgr (
    sid                         varchar2(2 char) default '01' not null enable,
    firma_nr                    number(2, 0) default 1 not null enable,
    lgr_platz                   varchar2(30 char) not null enable,
    lgr_platz_gruppe            varchar2(30 char),
    lgr_ort                     number(5, 0) default 1 not null enable,
    lgr_dim_g                   number(4, 0) default 1 not null enable,
    lgr_dim_r                   number(4, 0) default 1 not null enable,
    lgr_dim_p                   number(4, 0) default 1 not null enable,
    lgr_dim_e                   number(4, 0) default 1 not null enable,
    lgr_dim_t                   number(4, 0) default 1 not null enable,
    lgr_dim_platz               number(21, 0) not null enable,
    lgr_dim_fifo_nr             number(*, 5),
    lgr_typ                     varchar2(12 char) not null enable,
    lgr_verwendung              varchar2(10 char) not null enable,
    lgr_res_strat               varchar2(1 char),
    lgr_vol_hoehe               number(*, 3) not null enable,
    lgr_vol_breite              number(*, 3) not null enable,
    lgr_vol_tiefe               number(*, 3) not null enable,
    lgr_frei_hoehe              number(*, 3) not null enable,
    lgr_frei_breite             number(*, 3) not null enable,
    lgr_frei_tiefe              number(*, 3) not null enable,
    lgr_max_te                  number(*, 0) not null enable,
    lgr_akt_te                  number(*, 0) default 0 not null enable,
    lgr_dispo_einl_te           number(*, 0) default 0 not null enable,
    lgr_dispo_ausl_te           number(*, 0) default 0 not null enable,
    lgr_max_kg                  number(*, 6) not null enable,
    lgr_akt_kg                  number(*, 6) default 0 not null enable,
    lgr_dispo_einl_kg           number(*, 6) default 0 not null enable,
    lgr_dispo_ausl_kg           number(*, 6) default 0 not null enable,
    lgr_dat_erstellt            date,
    lgr_usr_id_erstellt         number(*, 0),
    lgr_dat_erst_belegt         date,
    lgr_dat_l_inventur          date,
    res_ls_login_name           varchar2(50 char),
    res_artikel_id              number(*, 0),
    res_string                  varchar2(80 char),
    gesperrt                    varchar2(1 char) default 'F' not null enable,
    gesp_grund                  varchar2(30 char),
    abc                         number(*, 0) default 1 not null enable,
    gruppe                      varchar2(30 char),
    wert_klasse                 number(*, 5),
    gefahren_klasse             number(*, 5),
    hrl_lag_max_pal_a           number(*, 0),
    hrl_lag_max_pal_i           number(*, 0),
    lte_namen                   varchar2(300 char),
    lte_namen_cfg               varchar2(300 char),
    lgr_platz_gruppe_gegenueber varchar2(30 char),
    lgr_temp                    number(*, 5) default 0,
    waren_typen_cfg             varchar2(30 char) default 'FW;' not null enable,
    res_art_statisch            varchar2(1 char) default 'T' not null enable,
    lgr_einl_te_verfueg         number(*, 5) default 0 not null enable,
    res_res_string_statisch     varchar2(1 char) default 'F' not null enable,
    lgr_order_res_te            number(*, 0),
    lgr_gruppe_id               number(*, 0),
    aktivierung_prio            number(*, 5),
    uml_erlaubt                 varchar2(1 char),
    anz_uml                     number(*, 0),
    lgr_verwendung_proj         varchar2(10 char),
    lgr_dispo_einl_frei_hoehe   number(*, 3),
    akt_inventur_id             number(*, 0),
    letzte_inventur_id          number(*, 0),
    letzte_inventur_datum       date,
    letzte_inventur_login_id    number(*, 0),
    lgr_platz_eti_pfeil_richt   varchar2(1 char),
    flaechen_stellplatz         varchar2(1 char) default 'F',
    wa_menge_ueberlief          varchar2(1 char),
    lgr_einl_te_verfueg_gruppe  number(*, 5),
    wa_typ                      varchar2(10 char),
    lgr_pos_x                   number(*, 5),
    lgr_pos_y                   number(*, 5),
    lgr_min_lte_hoehe           number(*, 3),
    lgr_min_lte_breite          number(*, 3),
    lgr_min_lte_tiefe           number(*, 3),
    owner_address_id            number(*, 0),
    lgr_kg_gruppe               varchar2(30 char),
    transport_einheit           varchar2(10 char) default 'LTE' not null enable,
    change_date                 date default sysdate not null enable,
    change_login_id             number(*, 0),
    einl_ort_default_liste      varchar2(100 char)
);

alter table dirkspzm32.lvs_lgr
    add constraint check_flaechen_stellplatz
        check ( flaechen_stellplatz in ( 'F', 'T' ) ) enable;

alter table dirkspzm32.lvs_lgr
    add constraint check_lgr_abc
        check ( abc in ( 1, 2, 3 ) ) enable;

alter table dirkspzm32.lvs_lgr
    add constraint check_lgr_gesperrt
        check ( gesperrt in ( 'F', 'G', 'N', 'M', 'X' ) ) enable;

alter table dirkspzm32.lvs_lgr
    add constraint check_lgr_typ
        check ( lgr_typ in ( 'SAT1', 'SAT_EPL1', 'SAT_EPL2', 'EPL1', 'KANAL1',
                             'KANBKL1', 'BKL1', 'REG_FACH1', 'SEG1', 'SEG_DUEDO1',
                             'DURCHL1', 'PP_EPL1', 'STAP_FLAE1', 'STAP_FLAE2' ) ) enable;

alter table dirkspzm32.lvs_lgr
    add constraint check_lgr_uml_erlaubt
        check ( uml_erlaubt in ( 'T', 'F', 'R' ) ) enable;

alter table dirkspzm32.lvs_lgr
    add constraint check_lgr_verwendung
        check ( lgr_verwendung in ( 'Lager', 'WE', 'WA', 'EP', 'Puffer',
                                    'WEP', 'LagerP' ) ) enable;

alter table dirkspzm32.lvs_lgr
    add constraint check_lgr_waren_typen_cfg
        check ( waren_typen_cfg like ( '%FW;%' )
                or waren_typen_cfg like ( '%RW;%' )
                or waren_typen_cfg like ( '%HW;%' ) ) enable;

alter table dirkspzm32.lvs_lgr
    add constraint check_lgr_wa_menge_ueberlief
        check ( wa_menge_ueberlief in ( 'F', 'T' ) ) enable;

alter table dirkspzm32.lvs_lgr
    add constraint check_lvs_lager_uml_erlaubt
        check ( uml_erlaubt in ( 'T', 'F', 'R' ) ) enable;

alter table dirkspzm32.lvs_lgr
    add constraint check_lvs_lgr_wa_typ
        check ( wa_typ in ( 'LDPR', 'LDPO', 'BDEPUSH', 'BDEICEPUSH' )
                or wa_typ is null ) enable;

alter table dirkspzm32.lvs_lgr
    add constraint check_res_res_string_statisch
        check ( res_res_string_statisch in ( 'F', 'T' ) ) enable;

alter table dirkspzm32.lvs_lgr
    add constraint pk_lvs_lgr primary key ( lgr_platz )
        using index enable;


